  ('dietitian-moex-07069', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者為紅血球細胞糖解反應（glycolysis）之中間產物，其存在可降低血紅蛋白（hemoglobin）與氧氣 之親和力？ 2,3-bisphosphoglycerate   1,3-bisphosphoglycerate glyceraldehyde-3-phosphate  fructose-2,6-bisphosphate', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07070', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '糖解作用（glycolysis）中，下列那些酵素催化之反應可生成 ATP？①phosphofructokinase', '["phosphoglycerate kinase", "hexokinase", "pyruvate kinase", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07071', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', 'Pyruvate decarboxylase可催化酵母菌無氧糖解作用（anaerobic glycolysis）之起始反應，下列何者為此酵 素所需之輔酶？ biotin  lipoic acid  pyridoxal phosphate  thiamine pyrophosphate', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07072', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '甘油生合成之調節與體內脂質代謝有密切相關，以糖皮質固醇而言，此激素可藉由調節下列何種酵素進 而調控肝臟和脂肪細胞的甘油生合成？ 丙酮酸羧化酶（pyruvate carboxylase） 磷酸烯醇丙酮酸羧化酶（PEP carboxylase） 甘油醛-3-磷酸去氫酶（glyceraldehyde-3-phosphate dehydrogenase） 甘油激酶（glycerol kinase）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07073', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', 'TZD（thiazolidinediones）是常用以治療糖尿病的藥物，關於其治療原理的敘述，下列何者錯誤？ 可降低血中游離脂肪酸並提高胰島素敏感性 可促進脂肪組織合成三酸甘油酯並減少游離脂肪酸之釋放 可促進脂肪組織的甘油新生作用 可抑制脂肪組織的PPARγ 活性進而抑制PEPCK活性', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
